INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-043', 'Geriatric', 'A 79-year-old man is undergoing emergent open repair of an incarcerated inguinal hernia under general anesthesia. His history includes well-controlled hypertension, mild hearing loss, and a baseline Montreal Cognitive Assessment (MoCA) score of 24. The case is uncomplicated. On postoperative day 1 the nurse reports that he is intermittently inattentive, believes he is at home, and was agitated overnight but calm and oriented this morning. Vitals are stable, SpO2 96% on room air, and a basic metabolic panel, glucose, and urinalysis are unremarkable. Which feature MOST strongly distinguishes this presentation as postoperative delirium rather than postoperative cognitive dysfunction or dementia?', '[{"text":"The presence of a low baseline MoCA score of 24 before surgery","label":"A","correct":false,"rationale":"A preoperative MoCA of 24 indicates mild baseline cognitive impairment, which is a risk factor for delirium but is not itself the distinguishing feature of the acute syndrome."},{"text":"The agitation occurring specifically at night","label":"B","correct":false,"rationale":"Nocturnal worsening (sundowning) is common in delirium but also occurs in dementia, so it does not by itself establish the diagnosis."},{"text":"The acute onset and fluctuating course of inattention and altered awareness over hours to a day","label":"C","correct":true,"rationale":"Correct — delirium is defined by an acute, fluctuating disturbance of attention and awareness, distinguishing it from the gradual, stable decline of dementia and the subtle, persistent deficits of postoperative cognitive dysfunction."},{"text":"The patient''s age greater than 75 years","label":"D","correct":false,"rationale":"Advanced age is a major predisposing risk factor for delirium but is not a diagnostic feature of the acute syndrome itself."},{"text":"The need to formally measure deficits weeks later with neuropsychological testing","label":"E","correct":false,"rationale":"Delayed neuropsychological testing is how postoperative cognitive dysfunction is detected, not how acute delirium is identified at the bedside."}]'::jsonb, 'C', 'Postoperative delirium is a clinical diagnosis defined by an ACUTE, FLUCTUATING disturbance of attention and awareness with a change from baseline cognition, often screened with tools such as the Confusion Assessment Method (CAM). This temporal pattern separates it from dementia (insidious, progressive, stable over a single day) and from postoperative cognitive dysfunction (a more subtle, persistent decline detected only by formal neuropsychological testing weeks later). Predisposing factors (older age, baseline cognitive impairment, sensory deficits) raise risk but are not the diagnostic criterion; first-line management is to identify and treat precipitants and apply nonpharmacologic measures (reorientation, sleep hygiene, early mobilization, sensory aids) before considering pharmacologic therapy.', '{}'::jsonb, 'Subspecialty Care', 'Perioperative neurocognitive disorders — distinguishing postoperative delirium from POCD/dementia', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK534831/","source":"Postoperative Delirium (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-044', 'Geriatric', 'An 83-year-old woman (weight 52 kg) presents for elective total hip arthroplasty under general anesthesia. Her comorbidities include controlled hypertension and an estimated glomerular filtration rate of 48 mL/min/1.73 m2. You plan a propofol induction and intend to maintain neuromuscular blockade. Considering the physiologic changes of aging, which dosing strategy is MOST appropriate?', '[{"text":"Use a standard adult induction dose of propofol per kilogram because central nervous system sensitivity is unchanged with age","label":"A","correct":false,"rationale":"The aged brain is more sensitive to propofol and elderly patients have a smaller, more slowly mixing central compartment, so a standard weight-based bolus risks profound hypotension and overdose."},{"text":"Give a larger propofol bolus to overcome the increased volume of distribution of lipophilic drugs in the elderly","label":"B","correct":false,"rationale":"Although increased body fat does raise the volume of distribution and prolong elimination half-life, this calls for a smaller, more slowly titrated dose, not a larger bolus, because the initial distribution and brain sensitivity dominate the induction response."},{"text":"Select pancuronium for maintenance because its long duration reduces the need for redosing in lengthy cases","label":"C","correct":false,"rationale":"Pancuronium is renally eliminated and its action is markedly prolonged in age-related renal impairment, making it a poor choice in this patient."},{"text":"Reduce the propofol induction dose and titrate slowly, and choose cisatracurium for neuromuscular blockade","label":"D","correct":true,"rationale":"Correct — the elderly require lower, slowly titrated induction doses owing to increased CNS sensitivity and slower circulation, and cisatracurium undergoes organ-independent Hofmann elimination, avoiding accumulation despite reduced renal function."},{"text":"Choose rocuronium and plan a fixed redosing schedule identical to that used in young adults","label":"E","correct":false,"rationale":"Aging prolongs the duration of aminosteroid relaxants and slows recovery, so fixed young-adult redosing intervals risk residual paralysis; dosing should instead be guided by quantitative train-of-four monitoring."}]'::jsonb, 'D', 'Aging increases pharmacodynamic sensitivity of the brain to hypnotics and opioids while reducing lean body mass, total body water, hepatic and renal clearance, and increasing body fat. The practical result is that induction agents like propofol should be given in REDUCED doses and titrated slowly, both because of heightened CNS sensitivity and a prolonged circulation time that delays the peak effect. For neuromuscular blockade, cisatracurium is attractive because Hofmann elimination is independent of hepatic and renal function, whereas renally cleared relaxants (pancuronium) and, to a lesser extent, hepatically dependent agents accumulate; quantitative neuromuscular monitoring is essential to avoid residual block.', '{}'::jsonb, 'Subspecialty Care', 'Pharmacology of aging — altered pharmacokinetics/pharmacodynamics and drug selection', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572137/","source":"Anesthetic Considerations in the Geriatric Population (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-045', 'Geriatric', 'An 81-year-old man with long-standing hypertension and preserved ejection-fraction heart failure presents for transurethral resection of a bladder tumor under general anesthesia. Echocardiography shows concentric left ventricular hypertrophy, an ejection fraction of 60%, and grade II diastolic dysfunction. After induction and positioning, his blood pressure falls to 78/52 mmHg and his rhythm converts to atrial fibrillation at 140 beats/min. Which intervention is MOST appropriate given his underlying cardiac physiology?', '[{"text":"Administer a generous afterload-reducing dose of nitroglycerin to lower the elevated systemic pressures","label":"A","correct":false,"rationale":"Aggressive vasodilation drops preload and coronary perfusion pressure in a stiff, preload-dependent ventricle and would worsen the existing hypotension."},{"text":"Give a large dexmedetomidine bolus to slow the heart rate through central sympatholysis","label":"B","correct":false,"rationale":"A dexmedetomidine bolus can cause marked bradycardia and hypotension and is not an appropriate acute treatment for hemodynamically significant tachyarrhythmia in this unstable patient."},{"text":"Start a dobutamine infusion to augment contractility because the problem is systolic pump failure","label":"C","correct":false,"rationale":"The ejection fraction is preserved and the problem is impaired relaxation and lost atrial contribution, so an inotrope adds little and its chronotropy can further shorten diastolic filling."},{"text":"Withhold treatment and permit deliberate hypotension to reduce surgical bleeding","label":"D","correct":false,"rationale":"Permissive hypotension is dangerous in an elderly patient with hypertrophy and diastolic dysfunction who depends on adequate perfusion pressure, and it ignores the destabilizing new tachyarrhythmia."},{"text":"Restore sinus rhythm or control the ventricular rate while maintaining adequate preload and afterload","label":"E","correct":true,"rationale":"Correct — the noncompliant, hypertrophied ventricle depends on the atrial kick and an adequate diastolic filling period, so a rapid loss of sinus rhythm is poorly tolerated and rate/rhythm control plus preserved filling pressures restores output."}]'::jsonb, 'E', 'Aging and chronic hypertension produce a stiff, hypertrophied left ventricle with diastolic dysfunction, which is exquisitely dependent on the atrial contribution to filling (the ''atrial kick'') and on a sufficiently long diastolic period. New-onset atrial fibrillation with a rapid ventricular response removes the atrial kick and shortens diastole, sharply reducing stroke volume and causing hypotension. The correct strategy is to restore sinus rhythm or control the rate while preserving preload and an adequate afterload/coronary perfusion pressure; vasodilators, unnecessary inotropes, and deliberate hypotension all worsen the picture in this preload-dependent, noncompliant ventricle.', '{}'::jsonb, 'Subspecialty Care', 'Cardiovascular physiology of aging — diastolic dysfunction and intraoperative hemodynamics', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572137/","source":"Anesthetic Considerations in the Geriatric Population (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-046', 'Principles & Preop', 'A healthy 28-year-old woman (ASA II for well-controlled asthma) is scheduled for an elective laparoscopic cholecystectomy at 11:00 AM. She is anxious about being hungry and asks the preoperative clinic what she may eat and drink beforehand. She has no history of gastroparesis, reflux, or prior difficult intubation, and her BMI is 24. Following current ASA preoperative fasting recommendations for elective procedures in patients without increased aspiration risk, which instruction is correct?', '[{"text":"She must remain strictly NPO for everything, including water, after midnight","label":"A","correct":false,"rationale":"Incorrect: blanket ''NPO after midnight'' is outdated and leads to unnecessarily prolonged fasting; clear liquids are allowed up to 2 hours before surgery."},{"text":"She may drink milk or a latte with milk up until 2 hours before surgery because dairy is a clear liquid","label":"B","correct":false,"rationale":"Incorrect: milk (other than the small amount in coffee or tea) is treated like a solid/fatty meal and is not a clear liquid, requiring a longer fast."},{"text":"She may eat a fried egg and bacon up until 6 hours before surgery as a light meal","label":"C","correct":false,"rationale":"Incorrect: fried or fatty foods and meat prolong gastric emptying and require an 8-hour fast, not the 6-hour light-meal window."},{"text":"She may have a light meal such as toast up until 6 hours before surgery and clear liquids up until 2 hours before surgery","label":"D","correct":true,"rationale":"Correct: ASA guidance permits a light meal up to 6 hours preoperatively and clear liquids up to 2 hours preoperatively for patients without increased aspiration risk."},{"text":"Because she has asthma, she should fast from all liquids for at least 8 hours to minimize aspiration risk","label":"E","correct":false,"rationale":"Incorrect: well-controlled asthma does not constitute an increased aspiration risk, and prolonging the clear-liquid fast confers no benefit."}]'::jsonb, 'D', 'ASA fasting guidance for elective patients without increased aspiration risk follows the familiar 2-4-6-8 framework: clear liquids up to 2 hours, breast milk up to 4 hours, infant formula/nonhuman milk and a light meal up to 6 hours, and fried/fatty foods or meat up to 8 hours. The 2023 modular update reaffirms clear liquids (which may contain carbohydrate, with or without protein) up to 2 hours and encourages avoiding needlessly prolonged fasting. Milk other than the trace amount in coffee or tea is handled as a solid because its fat content delays gastric emptying.', '{}'::jsonb, 'Subspecialty Care', 'Preoperative fasting guidelines and aspiration risk', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK580524/","source":"Gastric Ultrasound (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-047', 'Regional & Pain', 'A 92-kg woman undergoes cesarean delivery under spinal anesthesia. For multimodal analgesia the surgical team requests bilateral transversus abdominis plane (TAP) blocks at the end of the case using ropivacaine. The student anesthetist is calculating a safe total dose and counseling the team on monitoring. Which consideration is most important when performing bilateral TAP blocks in this patient?', '[{"text":"TAP blocks deposit anesthetic into a poorly vascularized fascial plane, so systemic absorption is negligible and dose limits can be disregarded","label":"A","correct":false,"rationale":"Incorrect; the TAP is a relatively vascular plane and large volumes are used bilaterally, producing clinically meaningful systemic absorption."},{"text":"Peak plasma concentration occurs immediately at injection, so any toxicity will be apparent before the patient leaves the operating room","label":"B","correct":false,"rationale":"Incorrect; peak plasma levels after TAP block typically occur around 30 minutes after injection, so delayed toxicity can appear after the patient leaves the room."},{"text":"Epinephrine should never be added to the local anesthetic for a TAP block because it has no effect on absorption","label":"C","correct":false,"rationale":"Incorrect; epinephrine can slow systemic absorption and serves as an intravascular marker, so its use is reasonable rather than contraindicated."},{"text":"Pregnancy increases the safe maximum dose of ropivacaine, allowing higher total milligram limits than in non-pregnant adults","label":"D","correct":false,"rationale":"Incorrect; pregnancy does not raise the safe ceiling and parturients have actually shown some of the highest peak plasma levels and symptoms after TAP blocks."},{"text":"Because large volumes are injected into a vascular plane, peak plasma levels can approach or exceed toxic thresholds, so total dose must respect weight-based maximums and patients monitored for LAST","label":"E","correct":true,"rationale":"Correct; bilateral TAP blocks use large local-anesthetic volumes absorbed from a vascular plane, with peak plasma concentrations typically around 30 minutes that may approach toxic ranges, mandating dose calculation and post-block monitoring."}]'::jsonb, 'E', 'The TAP block requires relatively large local-anesthetic volumes, and when performed bilaterally the cumulative dose can be substantial. The neurovascular plane is well perfused, so systemic absorption is significant: peak plasma concentrations generally occur about 30 minutes after injection and have been documented to approach or exceed accepted toxic thresholds, with parturients showing some of the highest levels and symptoms of mild toxicity. Clinicians must calculate total dose against weight-based maximums, consider epinephrine to slow absorption, and monitor for delayed local anesthetic systemic toxicity well beyond the time of injection.', '{}'::jsonb, 'Subspecialty Care', 'Truncal/abdominal wall blocks: TAP block local anesthetic dosing and systemic absorption', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547730/","source":"Transversus Abdominis Plane Block (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Regional & Pain'),
('authored-batch-r20-048', 'Cardiac', 'A 74-year-old man with a single-chamber transvenous implantable cardioverter-defibrillator (ICD) placed 3 years ago for ischemic cardiomyopathy (EF 30%) presents for an open right hemicolectomy. He has an underlying sinus rhythm at 68/min and is NOT pacemaker-dependent. The surgeon plans to use monopolar electrocautery on the abdomen. A cardiology interrogation the day prior confirmed the device functions normally. The team forgoes reprogramming and instead plans to place a doughnut magnet over the device for the case. Which statement best describes what this magnet will do once it is positioned over the ICD during electrocautery?', '[{"text":"It will suspend antitachycardia therapy (shock and ATP detection) without altering the bradycardia pacing mode","label":"A","correct":true,"rationale":"Correct: in essentially all ICDs the magnet inhibits tachyarrhythmia detection/therapy while leaving the programmed bradycardia pacing mode unchanged, so electrocautery noise cannot trigger an inappropriate shock."},{"text":"It will reprogram the device to asynchronous DOO pacing to prevent oversensing-induced inhibition","label":"B","correct":false,"rationale":"A magnet over an ICD suspends tachytherapy detection but does NOT change the pacing mode to asynchronous, unlike a magnet over a standalone pacemaker."},{"text":"It will both suspend shock delivery and convert any bradycardia pacing to an asynchronous mode","label":"C","correct":false,"rationale":"A magnet suspends tachytherapy in an ICD but has no effect on its bradycardia pacing parameters, so any pacing remains in its programmed demand mode."},{"text":"It will have no effect because ICDs ignore external magnets entirely","label":"D","correct":false,"rationale":"ICDs do respond to magnets by suspending tachytherapy; the response simply differs from the asynchronous-pacing response seen with standalone pacemakers."},{"text":"It will trigger an immediate diagnostic shock to test lead integrity before surgery","label":"E","correct":false,"rationale":"A magnet suspends, rather than triggers, shock therapy; it never delivers a defibrillation as a ''test.''"}]'::jsonb, 'A', 'For a non-pacemaker-dependent patient, a magnet over an ICD is an accepted intraoperative strategy: it suspends tachyarrhythmia detection so electrocautery EMI cannot be misread as VF and provoke an inappropriate shock. Crucially, the magnet does NOT place the ICD into asynchronous bradycardia pacing the way it would for a standalone pacemaker — so a magnet is not protective against EMI-induced pacing inhibition in a pacemaker-dependent ICD patient, who instead needs reprogramming to an asynchronous mode. Knowing the differential magnet response of pacemakers versus ICDs is central to perioperative CIED management.', '{}'::jsonb, 'Subspecialty Care', 'Perioperative management of cardiac implantable electronic devices (ICD magnet response and electromagnetic interference)', 'medium', '[{"url":"https://www.openanesthesia.org/aicds/","source":"Cardiac Implantable Electronic Devices: Internal Cardioverter-Defibrillators (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Cardiac');
